insert into public.projects(slug,title_en,title_bn,summary_en,summary_bn,status,published,featured,sort_order,category,year,technologies,objectives_en,results_en) values
('batch-type-grain-dryer','Batch Type Grain Dryer','ব্যাচ টাইপ গ্রেইন ড্রায়ার','Reliable batch drying concept intended to support better grain quality.','উন্নত শস্যমানের জন্য নির্ভরযোগ্য ব্যাচ শুকানোর ধারণা।','prototype',true,true,1,'Agro Engineering',2026,array['Engineering design','Prototyping'],'Develop a practical, maintainable grain drying solution.','Development is ongoing; verified results will be published when available.'),
('vacuum-paddy-collector','Vacuum Paddy Collector','ভ্যাকুয়াম ধান সংগ্রাহক','Efficient paddy collection concept with reduced manual handling.','কম শ্রমে দক্ষভাবে ধান সংগ্রহের ধারণা।','development',true,true,2,'Agro Engineering',2026,array['Engineering design','Prototyping'],'Develop a practical paddy collection system.','Development is ongoing.'),
('mobile-paddy-parboiling','Mobile Paddy Parboiling','মোবাইল ধান পারবয়েলিং','A flexible concept for mobile paddy processing.','মোবাইল ধান প্রক্রিয়াজাতকরণের একটি নমনীয় ধারণা।','research',true,false,3,'Agro Engineering',2026,array['Research','Engineering design'],'Explore mobile parboiling requirements.','Research is ongoing.'),
('smart-seed-system','Smart Seed System','স্মার্ট বীজ ব্যবস্থা','Precision tools for more confident seed management.','উন্নত বীজ ব্যবস্থাপনার জন্য নির্ভুল সরঞ্জামের ধারণা।','concept',true,false,4,'Smart Farming',2026,array['Product design','Smart farming'],'Document a practical seed management workflow.','Concept development is ongoing.'),
('grain-stirring-system','Grain Stirring System','শস্য নাড়াচাড়া ব্যবস্থা','Consistent airflow and grain management during drying.','শুকানোর সময় সমান বায়ুপ্রবাহ ও শস্য ব্যবস্থাপনার ধারণা।','prototype',true,false,5,'Agro Engineering',2026,array['Mechanical design','Prototyping'],'Improve consistency during grain drying.','Prototype work is ongoing.'),
('cnc-engineering','CNC Engineering','সিএনসি ইঞ্জিনিয়ারিং','Precision fabrication concepts for future-ready components.','নির্ভুল যন্ত্রাংশ তৈরির প্রকৌশল ধারণা।','active',true,false,6,'Engineering',2026,array['CNC','Fabrication'],'Develop accurate and maintainable fabrication workflows.','Capabilities are being developed.')
